import React, { useState, useEffect } from 'react';
import { Spin, Button, Col, Divider, Dropdown, Form, Menu, message, Modal, Row, Tooltip, Flex } from 'antd';
import styles from './style.less';
import { MoreOutlined, PlusOutlined } from '@ant-design/icons';
import type { API } from '@/services/typings';
import { strategies, operateStrategy } from '@/services/api';
import { ModalForm, ProFormText } from '@ant-design/pro-form';
import { t } from '@/global';
import Devices, { AssignTarget } from './Devices';
import { useIntl, useModel } from '@umijs/max';
import { hasAnyPermToAssignStrategyToDevice, hasAnyPermAssignStrategyToUser, hasGlobalPermToAssignStrategyToDeviceGroup, hasPermDeviceGroupsView, hasPermStrategiesEdit, hasPermToViewUsersInGroup } from '@/pages/RoleList/permissionUtils';

const { Item } = Menu;

type AppProps = {
    listData: API.StrategyListItem[],
    setListData: React.Dispatch<React.SetStateAction<API.StrategyListItem[]>>
    current: string | undefined
    setCurrent: (item: string | undefined) => void
    handleUpdateStatus: (guid: string, enable: boolean, refreshLeft: () => void) => void
}

const App: React.FC<AppProps> = (props) => {
    const [newRenameDupModalVisible, setNewRenameDupModalVisible] = useState<boolean>(false);
    const [newRenameDup, setNewRenameDup] = useState<string>();
    const [newRenameDupFormRef] = Form.useForm();
    const [deleteModalVisible, setDeleteModalVisible] = useState<boolean>(false);
    const [deleteModalLoading, setDeleteModalLoading] = useState<boolean>(false);
    const [menuOperateItem, setMenuOperateItem] = useState<API.StrategyListItem>();
    const [deviceModalVisible, setDeviceModalVisible] = useState<boolean>(false);
    const [assignTarget, setAssignTarget] = useState<AssignTarget>(AssignTarget.Device);
    const [loading, setLoading] = useState(false);
    const intl = useIntl();
    const { initialState } = useModel('@@initialState');
    const canEdit = hasPermStrategiesEdit(initialState?.user);

    const plain = (text: string, defaultMessage = '') => t(`pages.Settings.Strategy.${text}`, true, defaultMessage || text, intl) as string;

    const refreshLeft = () => {
        setLoading(true);
        strategies().then((v) => {
            setLoading(false);
            if (!v || !v.length) {
                return;
            }
            const index_default = v.findIndex((item) => isDefaultStrategy(item));
            if (index_default > 0) {
                const tmp0 = v[0];
                v[0] = v[index_default];
                v[index_default] = tmp0;
            }
            props.setListData(v);
            if (v.length > 0 && (!props.current || v.findIndex(e => e.guid == props.current) < 0)) {
                props.setCurrent(v[0].guid);
            }
        });
    };

    useEffect(() => {
        refreshLeft();
    }, []);

    const getMenu = () => {
        return props.listData.map((item) => {
            const disabled = !item.status;
            let items = [];

            // Enable/Disable
            if (canEdit) {
                items.push(
                    <Menu.Item key="status" onClick={() => handleUpdateStatus(item)}>
                        {item.status ? plain('Disable') : plain('Enable')}
                    </Menu.Item>
                );
            }

            // Edit/View Devices
            if (!isDefaultStrategy(item)) {
                const edit_devices = hasAnyPermToAssignStrategyToDevice(initialState?.user);
                items.push(
                    <Menu.Item
                        key="devices"
                        onClick={() => {
                            setMenuOperateItem(item);
                            setDeviceModalVisible(true);
                            setAssignTarget(AssignTarget.Device);
                        }}
                    >
                        {t(edit_devices ? 'Edit Devices' : 'View Devices')}
                    </Menu.Item>
                );
            }

            // Edit/View Users
            if (!isDefaultStrategy(item) && hasPermToViewUsersInGroup(initialState?.user)) {
                const edit_users = hasAnyPermAssignStrategyToUser(initialState?.user);
                items.push(
                    <Menu.Item
                        key="users"
                        onClick={() => {
                            setMenuOperateItem(item);
                            setDeviceModalVisible(true);
                            setAssignTarget(AssignTarget.User);
                        }}
                    >
                        {t(edit_users ? 'Edit Users' : 'View Users')}
                    </Menu.Item>
                );
            }

            // Edit/View Device Groups
            if (!isDefaultStrategy(item) && hasPermDeviceGroupsView(initialState?.user)) {
                const edit_device_groups = hasGlobalPermToAssignStrategyToDeviceGroup(initialState?.user);
                items.push(
                    <Menu.Item
                        key="device-groups"
                        onClick={() => {
                            setMenuOperateItem(item);
                            setDeviceModalVisible(true);
                            setAssignTarget(AssignTarget.DeviceGroup);
                        }}
                    >
                        {t(edit_device_groups ? 'Edit Device Groups' : 'View Device Groups')}
                    </Menu.Item>
                );
            }

            // Rename
            if (canEdit && !isDefaultStrategy(item)) {
                items.push(
                    <Menu.Item
                        key="rename"
                        onClick={() => {
                            setMenuOperateItem(item);
                            setNewRenameDup('rename');
                            setNewRenameDupModalVisible(true);
                        }}
                    >
                        {plain('Rename')}
                    </Menu.Item>
                );
            }

            // Duplicate
            if (canEdit) {
                items.push(
                    <Menu.Item
                        key="duplicate"
                        onClick={() => {
                            setMenuOperateItem(item);
                            setNewRenameDup('dup');
                            setNewRenameDupModalVisible(true);
                        }}
                    >
                        {plain('Duplicate')}
                    </Menu.Item>
                );
            }

            // Delete
            if (canEdit && !isDefaultStrategy(item)) {
                items.push(
                    <Menu.Item
                        key="delete"
                        danger
                        onClick={() => {
                            setMenuOperateItem(item);
                            setDeleteModalVisible(true);
                        }}
                    >
                        {plain('Delete')}
                    </Menu.Item>
                );
            }

            return <Item key={item.guid} className={styles.menu_item}>
                <Row justify={"space-between"} gutter={[24, 0]}>
                    <Col span={18}>
                        <Row wrap={false}>
                            <Col flex={'none'}>
                                <div className={styles.colored_circle} style={{ background: disabled ? '#B2B2B2' : '#7FE9DE' }} />
                            </Col>
                            <Col flex={'auto'}>
                                <span style={{ display: 'inline-block', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', width: '100%', color: disabled ? '#B2B2B2' : undefined }}>{isDefaultStrategy(item) ? plain(item.name) : item.name}{disabled && ` (${plain("disabled")})`}</span>
                            </Col>
                        </Row>
                    </Col>
                    <Col span={6}>
                        <Row justify={"end"} wrap={false}>
                            <Col>
                                <Dropdown
                                    disabled={items.length === 0}
                                    overlay={
                                        <Menu>
                                            {items}
                                        </Menu>
                                    }
                                    arrow
                                >
                                    <Button
                                        className={styles.more}
                                        type="text"
                                        shape="circle"
                                        icon={<MoreOutlined />}
                                    />
                                </Dropdown>
                            </Col>
                            <Col>
                                <Tooltip title={`${t("applied device num", true)}: ${item.peer_count ?? 0}`}>
                                    <span style={{ display: 'inline-block', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis', width: '100%', color: disabled ? '#B2B2B2' : undefined }}>{item.peer_count ?? 0}</span>
                                </Tooltip>
                            </Col>
                        </Row>

                    </Col>
                </Row>


            </Item>
        });
    };

    const handleOperate = async (data: any, info: string) => {
        try {
            await operateStrategy({ data });
            message.success(info + ' success!');
            refreshLeft();
            return true;
        } catch (err) {
            message.error(err as any);
        }
        return false
    };

    const handleNew = async (name: string) => {
        const data = {
            action: 'new',
            name,
        };
        return handleOperate(data, 'Create');
    };

    const handleRename = async (name: string) => {
        if (menuOperateItem) {
            const data = {
                action: 'rename',
                guid: menuOperateItem.guid,
                name,
            };
            return handleOperate(data, 'Rename');
        }
        return false;
    };

    const handleDuplicate = async (name: string) => {
        if (menuOperateItem) {
            const data = {
                action: 'duplicate',
                guid: menuOperateItem.guid,
                name,
            };
            return handleOperate(data, 'Duplicate');
        }
        return false;
    };

    const handleDelete = async () => {
        setDeleteModalLoading(true);
        if (menuOperateItem) {
            const data = {
                action: 'delete',
                guid: menuOperateItem.guid,
            };
            handleOperate(data, 'Delete');
        }
        setDeleteModalLoading(false);
        setDeleteModalVisible(false);
    };

    const handleUpdateStatus = async (item: API.StrategyListItem) => {
        props.handleUpdateStatus(item.guid, !item.status, refreshLeft);
    }

    const handleNewRenameDupFinish = async (value: Record<string, any>) => {
        await newRenameDupFormRef.validateFields(['name']);
        let res = false;
        if (newRenameDup === 'new') {
            res = await handleNew(value.name);
        } else if (newRenameDup == 'rename') {
            res = await handleRename(value.name);
        } else {
            res = await handleDuplicate(value.name);
        }
        if (res) {
            setNewRenameDupModalVisible(false);
        }
    }


    const newRenameDupForm = () => (
        <ModalForm
            form={newRenameDupFormRef}
            title={
                newRenameDup === 'new'
                    ? plain('New strategy')
                    : newRenameDup == 'rename'
                        ? `${plain('Rename strategy')} ${menuOperateItem?.name}`
                        : `${plain('Duplicate strategy')} ${menuOperateItem?.name}`
            }
            visible={newRenameDupModalVisible}
            width={400}
            onVisibleChange={(visible) => {
                if (visible) {
                    newRenameDupFormRef.resetFields();
                    if (newRenameDup == 'rename') {
                        newRenameDupFormRef.setFieldValue(['name'], menuOperateItem?.name);
                    } else {
                        newRenameDupFormRef.setFieldValue(['name'], '');
                    }

                }
                setNewRenameDupModalVisible(visible);
            }}
            onFinish={handleNewRenameDupFinish}
            onKeyDown={async (e) => {
                if (e.key == 'Enter') {
                    e.preventDefault();
                    await newRenameDupFormRef.validateFields(['name']);
                    const value = newRenameDupFormRef.getFieldsValue();
                    if (!value.name) return;
                    handleNewRenameDupFinish(value);
                }
            }}

        >
            <ProFormText
                fieldProps={{ autoComplete: 'off' }}
                rules={[
                    {
                        required: true,
                        whitespace: true,
                    },
                    {
                        min: 4,
                        max: 300,
                    },
                ]}
                width="md"
                name="name"
                label={t('Name', true)}
            />
        </ModalForm >
    );

    return (
        (<div>
            {loading && <div style={{ position: "absolute", width: '100%', textAlign: "center" }}><Spin /></div>}
            <Flex style={{ height: '100%' }}>
                <div className={styles.leftMenu}>
                    <div>
                        <span className={styles.menu_title}>{plain('Strategy list')}</span>
                        <Button
                            hidden={!canEdit}
                            onClick={() => {
                                setNewRenameDup('new');
                                setNewRenameDupModalVisible(true);
                            }}
                            className={styles.menu_title_add}
                            type="text"
                            shape="circle"
                            icon={<PlusOutlined />}
                        />
                    </div>
                    <Divider />
                    <Menu
                        mode="vertical"
                        selectedKeys={props.current ? [props.current] : []}
                        onClick={({ key }) => {
                            props.setCurrent(key);
                        }}
                        style={{ borderRight: 'none' }}
                    >
                        {getMenu()}
                    </Menu>
                </div>
                <Divider type={'vertical'} style={{ marginLeft: '0em', height: '100%' }} />
            </Flex>
            {newRenameDupForm()}
            <Modal
                title={`${t('Delete', true)} ${menuOperateItem?.name}`}
                open={deleteModalVisible}
                onOk={handleDelete}
                onCancel={() => {
                    setDeleteModalVisible(false);
                }}
                confirmLoading={deleteModalLoading}
            >
                <span>{plain('delete_strategy_tip', 'Are you sure you want to delete strategy "' + menuOperateItem?.name + '"?')}</span>
            </Modal>
            {
                menuOperateItem && deviceModalVisible ? (
                    <Devices
                        visible={deviceModalVisible}
                        setVisible={setDeviceModalVisible}
                        strategy={menuOperateItem.guid}
                        strategyName={menuOperateItem.name}
                        closeChangedCallback={refreshLeft}
                        assignTarget={assignTarget}
                    />
                ) : (
                    <div />
                )
            }
        </div>)
    );
};
export default App;


const isDefaultStrategy = (item: { name: string }) => {
    return item.name === 'Default';
}


