import type { RadioChangeEvent } from "antd";
import { Checkbox, Col, Radio, Row, Space, theme } from "antd";
import { isString } from "lodash";
import { useIntl } from "@umijs/max";
import { ConfigOptionKey, configOptions } from "./common";
const { useToken } = theme;
import { t } from "@/global";

type AppProps = {
    editing: boolean,
    displayConfigOptions: Record<string, string>;
    setDisplayConfigOptions: React.Dispatch<React.SetStateAction<Record<string, string>>>;
}

type PermMap = {
    label: string,
    key: string,
}

const App: React.FC<AppProps> = (props) => {
    const intl = useIntl();
    const { token } = useToken();

    const plain = (text: string, defaultMessage = '') => t(`pages.Settings.Strategy.${text}`, true, defaultMessage || text, intl) as string;

    const onAccessRadioChange = (e: RadioChangeEvent) => {
        const tmp = { ...props.displayConfigOptions };
        let accessMode;
        switch (e.target.value) {
            case 1:
                accessMode = 'full'
                break;
            case 2:
                accessMode = 'view'
                break;
            default:
                accessMode = ''
                break;
        }
        tmp[ConfigOptionKey.ACCESS_MODE] = accessMode;
        props.setDisplayConfigOptions(tmp);
    };

    const accessRadios = () => {
        const accessMode = props.displayConfigOptions[ConfigOptionKey.ACCESS_MODE];

        let value = 0;
        if (accessMode === "full") {
            value = 1;
        } else if (accessMode === "view") {
            value = 2;
        }

        const radioOptions = [
            { label: plain('Custom'), value: 0 },
            { label: plain('Full access'), value: 1 },
            { label: plain('Screen share'), value: 2 },
        ];

        return (
            <Radio.Group onChange={props.editing ? onAccessRadioChange : undefined} value={value}>
                <Space direction="horizontal">
                    {radioOptions.map(option => (
                        <Radio key={option.value} disabled={!props.editing} value={option.value}>
                            <span>{option.label}</span>
                        </Radio>
                    ))}
                </Space>
            </Radio.Group>
        );
    }

    const permVisible = () => {
        const accessMode = props.displayConfigOptions[ConfigOptionKey.ACCESS_MODE];
        return !accessMode
    }

    const permNames: PermMap[] = [
        ConfigOptionKey.ENABLE_KEYBOARD,
        ConfigOptionKey.ENABLE_REMOTE_PRINTER,
        ConfigOptionKey.ENABLE_CLIPBOARD,
        ConfigOptionKey.ENABLE_FILE_TRANSFER,
        ConfigOptionKey.ENABLE_AUDIO,
        ConfigOptionKey.ENABLE_CAMERA,
        ConfigOptionKey.ENABLE_TERMINAL,
        ConfigOptionKey.ENABLE_TUNNEL,
        ConfigOptionKey.ENABLE_REMOTE_RESTART,
        ConfigOptionKey.ENABLE_RECORD_SESSION,
        ConfigOptionKey.ENABLE_BLOCK_INPUT,
        ConfigOptionKey.ALLOW_REMOTE_CONFIG_MODIFICATION,
    ].map((key) => configOptions[key]);

    const defaultValue = (key: string) => {
        if (key.startsWith('enable-')) {
            return true;
        }
        return false;
    }

    const onPermCheckBoxClick = (key: string, checked: boolean) => {
        const tmp = { ...props.displayConfigOptions };
        const dft = defaultValue(key);
        if (checked === dft) {
            tmp[key] = '';
        } else {
            tmp[key] = dft ? 'N' : 'Y';
        }
        props.setDisplayConfigOptions(tmp);
    };

    const getChecked = (key: string) => {
        const option = props.displayConfigOptions[key];
        const dft = defaultValue(key);
        if (isString(option)) {
            if (!option || option.length === 0) {
                return dft;
            } else {
                return !dft;
            }
        } else {
            return dft;
        }
    }

    const permCheckbox = () => permNames.map((v) => {
        const checked = getChecked(v.key);
        return <Col span={8} key={v.key}>
            <Checkbox
                checked={checked}
                disabled={!props.editing}
                onClick={(e) => onPermCheckBoxClick(v.key, !checked)}
            >
                <span>{plain(v.label)}</span>
            </Checkbox>
        </Col>
    }
    )

    const getRadiolabel = (label: string) => {
        return <span style={{ marginRight: 16, display: "inline-block", color: props.editing ? undefined : token.colorTextQuaternary }}>{plain(label) + " :"}</span>;
    }

    return <Row>
        {getRadiolabel('Permission type')}
        <Col>
            {accessRadios()}
        </Col>
        {permVisible() ?
            <Col>
                <div style={{ height: 16 }} />
                <Row>
                    {permCheckbox()}
                </Row>
            </Col> : null}
    </Row>

};


export default App;
