import React, { useState, useEffect } from 'react';
import { GridContent, PageContainer } from '@ant-design/pro-layout';
import { Button, message, Space, Typography, theme } from 'antd';
import styles from './style.less';
import type { API } from '@/services/typings';
import { updateStrategy, strategy, updateStrategyStatus, defaultStrategyOptions } from '@/services/api';
import Password from './Passsword';
import Security from './Security';
import Permission from './Permission';
import LeftMenu from './LeftMenu';
import { useIntl, useModel } from '@umijs/max';
import { t } from '@/global';
import Other from './Other';
import { ConfigOptionKey } from './common';
import { hasPermStrategiesEdit } from '@/pages/RoleList/permissionUtils';
const { useToken } = theme;

type StrategyOptions = {
  config_options: Record<string, string>;
  extra: Record<string, string>;
};

const config_option_keys: string[] = [
  ConfigOptionKey.ACCESS_MODE,
  ConfigOptionKey.ENABLE_KEYBOARD,
  ConfigOptionKey.ENABLE_REMOTE_PRINTER,
  ConfigOptionKey.ENABLE_CLIPBOARD,
  ConfigOptionKey.ENABLE_FILE_TRANSFER,
  ConfigOptionKey.ENABLE_AUDIO,
  ConfigOptionKey.ENABLE_CAMERA,
  ConfigOptionKey.ENABLE_TERMINAL,
  ConfigOptionKey.ENABLE_TUNNEL,
  ConfigOptionKey.ENABLE_REMOTE_RESTART,
  ConfigOptionKey.ENABLE_RECORD_SESSION,
  ConfigOptionKey.ENABLE_BLOCK_INPUT,
  ConfigOptionKey.ALLOW_REMOTE_CONFIG_MODIFICATION,
  ConfigOptionKey.APPROVE_MODE,
  ConfigOptionKey.VERIFICATION_METHOD,
  ConfigOptionKey.TEMPORARY_PASSWORD_LENGTH,
  ConfigOptionKey.ALLOW_NUMERIC_ONE_TIME_PASSWORD,
  ConfigOptionKey.ALLOW_HIDE_CM,
  ConfigOptionKey.ENABLE_LAN_DISCOVERY,
  ConfigOptionKey.DIRECT_SERVER,
  ConfigOptionKey.DIRECT_ACCESS_PORT,
  ConfigOptionKey.WHITELIST,
  ConfigOptionKey.ALLOW_AUTO_DISCONNECT,
  ConfigOptionKey.AUTO_DISCONNECT_TIMEOUT,
  ConfigOptionKey.ALLOW_REMOVE_WALLPAPER
]

const StrategyApp: React.FC = () => {
  const [listData, setListData] = useState<API.StrategyListItem[]>([]);
  const [current, setCurrent] = useState<string>();
  const [configOptions, setConfigOptions] = useState<Record<string, string>>({});
  const [displayConfigOptions, setDisplayConfigOptions] = useState<Record<string, string>>({});
  const [extra, setExtra] = useState<Record<string, string>>({});
  const [displayExtra, setDisplayExtra] = useState<Record<string, string>>({});
  const [editing, setEditing] = useState<boolean>(false);
  const intl = useIntl();
  const { token } = useToken();
  const { initialState } = useModel('@@initialState');
  const canEdit = hasPermStrategiesEdit(initialState?.user);

  const plain = (text: string, defaultMessage = '') => t(`pages.Settings.Strategy.${text}`, true, defaultMessage || text, intl) as string;

  const currentItem = () => {
    if (current) {
      return listData.find(e => e.guid === current);
    }
    return undefined;
  }

  const filter_config_options = (input: Record<string, string>) => {
    if (!input) input = {};
    const output: Record<string, string> = {};
    config_option_keys.map((k) => {
      if (input.hasOwnProperty(k)) {
        output[k] = input[k]
      } else {
        output[k] = '';
      }
    });
    return output;
  };

  const refreshRight = () => {
    const curItem = currentItem();
    if (curItem) {
      strategy({ guid: curItem.guid }).then((v) => {
        let tmp: StrategyOptions = { config_options: {}, extra: {} };
        try {
          tmp = JSON.parse(v.options || '{}');
        } catch (e) { }
        try {
          const config_options = filter_config_options(tmp.config_options || {});
          setConfigOptions(config_options);
          setDisplayConfigOptions(config_options);
          setExtra(tmp.extra);
          setDisplayExtra(tmp.extra);
        } catch (e) {
          message.error('Failed to read strategy: ' + e);
        }
      });
    }
  };
  useEffect(() => {
    refreshRight();
  }, [current]);

  useEffect(() => {
    if (process.env.NODE_ENV === 'development') {
      defaultStrategyOptions({}).then((v) => {
        let defaultOptions: StrategyOptions = { config_options: {}, extra: {} };
        try {
          defaultOptions = JSON.parse(v || '{}');
        } catch (e) { }
        const frontendConfigOptionKeys = config_option_keys;
        const backendConfigOptionKeys = Object.keys(defaultOptions.config_options);
        if (backendConfigOptionKeys.length !== frontendConfigOptionKeys.length) {
          message.error(`The frontend and backend config option lengths mismatch, ${frontendConfigOptionKeys.length} !== ${backendConfigOptionKeys.length}`);
        } else {
          for (let i = 0; i < backendConfigOptionKeys.length; i++) {
            if (frontendConfigOptionKeys.includes(backendConfigOptionKeys[i]) === false) {
              message.error(`Config option key ${backendConfigOptionKeys[i]} not found in frontend.`);
              break;
            }
          }
        }
      });
    }
  }, []);

  const handleUpdateSubmit = () => {
    const curItem = currentItem();
    if (!curItem) return;
    let config_options: Record<string, string> = { ...displayConfigOptions };
    // remove empty values
    config_options = Object.entries(config_options).reduce((newObj, [key, value]) => {
      if (value !== null && value !== undefined && value !== '') {
        newObj[key] = value;
      }
      return newObj;
    }, {} as Record<string, string>);
    const data = {
      config_options,
      extra: displayExtra,
    };
    setEditing(false);

    updateStrategy({ guid: curItem.guid }, { data }).then(() => {
      message.success("Update Strategy successfully.");
      refreshRight();
    }).catch((e) => {
      message.error(e);
    });
  };

  const handleUpdateStatus = (guid: string, enable: boolean, refreshLeft: () => void) => {
    const data = enable;
    updateStrategyStatus({ guid: guid }, { data }).then(() => {
      refreshLeft();
    }, (err) => {
      message.error(err);
    });
  };

  const handleUpdateCancel = () => {
    setDisplayConfigOptions(configOptions);
    setDisplayExtra(extra);
    setEditing(false);
  };

  const getRight = () => {
    const curItem = currentItem();
    if (!curItem) return (
      <div />
    );
    const disabledText = editing ? undefined : {
      color: token.colorTextQuaternary,
    };
    return (
      <div>
        <div className={styles.title}>
          {curItem.name === 'Default'
            ? plain(curItem.name)
            : <span>{curItem.name} <Typography.Text copyable code={true} style={{ fontSize: 12 }}>{curItem.guid}</Typography.Text></span>}

        </div>
        <Space size={10} direction="vertical">
          <div className={styles.subtitle} style={disabledText}>{plain('Permissions')}</div>
          <Permission
            editing={editing}
            displayConfigOptions={displayConfigOptions}
            setDisplayConfigOptions={setDisplayConfigOptions}
          />
          <div className={styles.subtitle} style={disabledText}>{plain('Password')}</div>
          <Password
            editing={editing}
            displayConfigOptions={displayConfigOptions}
            setDisplayConfigOptions={setDisplayConfigOptions}
          />
          <div className={styles.subtitle} style={disabledText}>{plain('Security')}</div>
          <Security
            editing={editing}
            displayConfigOptions={displayConfigOptions}
            setDisplayConfigOptions={setDisplayConfigOptions}
          />
          <div className={styles.subtitle} style={disabledText}>{plain('Other')}</div>
          <Other
            editing={editing}
            displayConfigOptions={displayConfigOptions}
            setDisplayConfigOptions={setDisplayConfigOptions}
          />
          <div id={styles.right_button_div} hidden={!canEdit}>
            {editing ? (
              <Space size={20}>
                <Button type="primary" onClick={handleUpdateSubmit}>
                  {plain('Submit')}
                </Button>
                <Button onClick={handleUpdateCancel}>{plain('Cancel')}</Button>
              </Space>
            ) : (
              <Button type="primary" onClick={() => setEditing(true)}>
                {plain('Edit')}
              </Button>
            )}
          </div>
        </Space>
      </div>
    )
  }

  const setCurrentWrap = (item: string | undefined) => {
    if (item != current) {
      setEditing(false);
    }
    setCurrent(item);
  }

  return (
    <PageContainer>
      <GridContent>
        <div className={styles.main} style={{ backgroundColor: token.colorBgContainer }}>
          <LeftMenu
            listData={listData}
            setListData={setListData}
            current={current}
            setCurrent={setCurrentWrap}
            handleUpdateStatus={handleUpdateStatus}
          />
          <div className={styles.right}>{getRight()}</div>
        </div>
      </GridContent>
    </PageContainer>
  );
};
export default StrategyApp;
