import { devices, users, assignStrategies, groups } from "@/services/api"
import { Button, Col, message, Modal, Row, Typography } from "antd"
import { useEffect, useRef, useState } from "react"
import { API } from '@/services/typings';
import ProTable, { ActionType } from "@ant-design/pro-table";
import { getTablePaginationConfig, GroupTypeDevice, t } from "@/global";
import { CloseOutlined } from "@ant-design/icons";
import { DEVICE_LIST_SORT_STATE_KEY, deviceColumns } from "@/pages/DeviceList/DevicesTable";
import { USER_LIST_SORT_STATE_KEY, userColumns } from "@/pages/UserList";
import { useModel } from "@umijs/max";
import { getLocalSortState, handleSortStateChange } from "@/components/Others/table_sort";
import { DEVICE_GROUP_LIST_SORT_STATE_KEY, deviceGroupColumns } from "@/pages/DeviceGroupList";
import { hasGlobalPermToAssignStrategyToDeviceGroup, canAssignStrategyToDevice, canAssignStrategyToUser, hasAnyPermAssignStrategyToUser, hasAnyPermToAssignStrategyToDevice } from "@/pages/RoleList/permissionUtils";

export enum AssignTarget {
  Device,
  User,
  DeviceGroup,
}

const assignTargetToFiled = (assignTarget: AssignTarget) => {
  switch (assignTarget) {
    case AssignTarget.Device:
      return "peers";
    case AssignTarget.User:
      return "users";
    case AssignTarget.DeviceGroup:
      return "groups";
  }
}

const assignTargetToRequest = (assignTarget: AssignTarget, sortState: API.SortState, setTotalRecords: (total: number) => void) => {
  switch (assignTarget) {
    case AssignTarget.Device:
      return async (params: any) => {
        const result = await devices(params, sortState);
        setTotalRecords(result.total || 0);
        return result;
      }
    case AssignTarget.User:
      return users;
    case AssignTarget.DeviceGroup:
      return async (params: any) => {
        params.type = GroupTypeDevice.toString();
        const res = await groups(params, undefined, undefined, sortState);
        return res;
      }
  }
}

const assignTargetToSortStateKey = (assignTarget: AssignTarget) => {
  switch (assignTarget) {
    case AssignTarget.Device:
      return DEVICE_LIST_SORT_STATE_KEY;
    case AssignTarget.User:
      return USER_LIST_SORT_STATE_KEY;
    case AssignTarget.DeviceGroup:
      return DEVICE_GROUP_LIST_SORT_STATE_KEY;
  }
}

type DevicesProps = {
  visible: boolean
  setVisible: React.Dispatch<React.SetStateAction<boolean>>
  strategy: string,
  strategyName: string,
  assignTarget: AssignTarget,
  closeChangedCallback: () => void;
}

const app: React.FC<DevicesProps> = (props) => {
  const [devs, setDevs] = useState<(API.DeviceListItem | API.UserListItem)[]>([]);
  const [selectedRowKeys, setSelectedRowKeys] = useState<string[]>([]);
  const [everChanged, setEverChanged] = useState<boolean>(false);
  const [totalRecords, setTotalRecords] = useState<number>(0);
  const [sortState, setSortState] = useState<API.SortState>(() => getLocalSortState(assignTargetToSortStateKey(props.assignTarget)));
  const actionRef = useRef<ActionType>();
  const { initialState } = useModel('@@initialState');

  useEffect(() => {
    if (props.visible) {
      actionRef.current?.reload();
    }
  }, [props.visible]);

  const onSave = async () => {
    const changeTochecked = devs.filter((d: API.DeviceListItem | API.UserListItem) => d.strategy !== props.strategy && selectedRowKeys.indexOf(d.guid) >= 0);
    if (changeTochecked.length > 0) {
      try {
        const data = {
          strategy: props.strategy,
        } as any;
        data[assignTargetToFiled(props.assignTarget)] = changeTochecked.map(v => v.guid);
        await assignStrategies({ data });
      } catch (e: any) {
        message.error(e);
        return;
      }
    }
    const changeToUnchecked = devs.filter((d: API.DeviceListItem | API.UserListItem) => d.strategy === props.strategy && selectedRowKeys.indexOf(d.guid) < 0);
    if (changeToUnchecked.length > 0) {
      try {
        let data = {} as any;
        data[assignTargetToFiled(props.assignTarget)] = changeToUnchecked.map(v => v.guid);
        await assignStrategies({ data });
      } catch (e: any) {
        message.error(e);
        return;
      }
    }
    let changedCount = changeTochecked.length + changeToUnchecked.length;
    message.success(`${changedCount} record${changedCount === 1 ? " is" : "s are"} successfully changed`)
    setEverChanged(true);
    actionRef.current?.reload();
  }

  const onReset = async () => {
    actionRef.current?.reset?.();
  }

  const saveButtonEnabled = () => {
    const changeTochecked = devs.filter((d: API.DeviceListItem | API.UserListItem) => d.strategy !== props.strategy && selectedRowKeys.indexOf(d.guid) >= 0);
    const changeToUnchecked = devs.filter((d: API.DeviceListItem | API.UserListItem) => d.strategy === props.strategy && selectedRowKeys.indexOf(d.guid) < 0);
    let changedCount = changeTochecked.length + changeToUnchecked.length;
    return changedCount > 0;
  }

  const onClose = () => {
    props.setVisible(false);
    setDevs([]);
    setSelectedRowKeys([]);
    if (everChanged) props.closeChangedCallback();
    setEverChanged(false);
  }

  const canReactChange = (): boolean => {
    if (props.assignTarget === AssignTarget.User) {
      return hasAnyPermAssignStrategyToUser(initialState?.user);
    } else if (props.assignTarget === AssignTarget.Device) {
      return hasAnyPermToAssignStrategyToDevice(initialState?.user);
    } else if (props.assignTarget === AssignTarget.DeviceGroup) {
      return hasGlobalPermToAssignStrategyToDeviceGroup(initialState?.user);
    }
    return true;
  }

  const checkBoxEnabled = (record: API.UserListItem | API.DeviceListItem | API.DeviceListItem): boolean => {
    if (props.assignTarget === AssignTarget.User) {
      return canAssignStrategyToUser(initialState?.user, record as API.UserListItem);
    } else if (props.assignTarget === AssignTarget.Device) {
      return canAssignStrategyToDevice(initialState?.user, record as API.DeviceListItem);
    } else if (props.assignTarget === AssignTarget.DeviceGroup) {
      return hasGlobalPermToAssignStrategyToDeviceGroup(initialState?.user);
    }
    return true;
  }

  const columns = props.assignTarget === AssignTarget.User ? userColumns({
    actionRef,
    myname: initialState?.user?.name,
    is_select: true,
    sortState,
    setSortState,
  }) : props.assignTarget === AssignTarget.Device ? deviceColumns({
    actionRef,
    user: initialState?.user,
    is_select: true,
    sortState,
    setSortState,
    totalRecords,
  }) : deviceGroupColumns({
    actionRef,
    showLinkName: (groupname: string) => false,
    sortState,
  });

  return <Modal
    visible={props.visible}
    width="90vw"
    style={{
      overflowX: "hidden",
    }}
    footer={saveButtonEnabled() ?
      <Row justify="center" gutter={16}>
        <Col>
          <Button onClick={onReset}>{t("Reset")}</Button>
        </Col>
        <Col>
          <Button onClick={onSave} type="primary">{t("Save")}</Button>
        </Col>
      </Row>
      : null}
    onCancel={onClose}
    destroyOnClose={true}
    title={<span>Add or remove {assignTargetToFiled(props.assignTarget)} for strategy <Typography.Text mark>{props.strategyName}</Typography.Text></span>}
    closeIcon={<CloseOutlined />}
  >
    <ProTable<API.DeviceListItem | API.UserListItem, API.PageParams>
      columnsState={{ persistenceType: 'localStorage', persistenceKey: 'edit' + (assignTargetToFiled(props.assignTarget) + '_columns_state') }}
      rowKey={"guid"}
      actionRef={actionRef}
      search={{ filterType: 'light' }}
      defaultSize="middle"
      columns={columns as any}
      request={assignTargetToRequest(props.assignTarget, sortState, setTotalRecords)}
      postData={(items: (API.DeviceListItem | API.UserListItem)[]) => {
        setDevs(items);
        setSelectedRowKeys(items.filter((i: API.DeviceListItem | API.UserListItem) => i.strategy === props.strategy).map((d) => d.guid));
        return items;
      }}
      rowSelection={{
        selectedRowKeys: selectedRowKeys,
        onChange: canReactChange() ? (selectedRowKeys) => {
          setSelectedRowKeys(selectedRowKeys as string[]);
        }
          : undefined,
        getCheckboxProps: (record) => ({
          disabled: !checkBoxEnabled(record),
        }),
        // preserveSelectedRowKeys: true,
      }}
      pagination={getTablePaginationConfig(`strategy_${assignTargetToFiled(props.assignTarget)}_list`)}
      style={{
        paddingLeft: '5vw', paddingRight: '5vw'
      }}
      onChange={(_, __, sorter) => handleSortStateChange(sorter, actionRef, assignTargetToSortStateKey(props.assignTarget), setSortState)}
    />
  </Modal >
}

export default app;

