import { Button, Checkbox, Col, Form, InputNumber, Modal, Row, Tooltip } from 'antd';
import React, { useState } from 'react';
import { useIntl } from '@umijs/max';
import { WarningOutlined } from '@ant-design/icons';
import { isString } from 'lodash';
import { ProFormTextArea } from '@ant-design/pro-form';
import { ConfigOptionKey, configOptions } from './common';
import { t } from '@/global';

type AppProps = {
  editing: boolean;
  displayConfigOptions: Record<string, string>;
  setDisplayConfigOptions: React.Dispatch<React.SetStateAction<Record<string, string>>>;
};

const App: React.FC<AppProps> = (props) => {
  const intl = useIntl();
  const [whiltelistModalOpen, setWhiltelistModalOpen] = useState<boolean>(false);
  const [whiltelistError, setWhiltelistError] = useState('');
  const [whiltelistForm] = Form.useForm();

  const plain = (text: string, defaultMessage = '') => t(`pages.Settings.Strategy.${text}`, true, defaultMessage || text, intl) as string;

  // reverse: enable -> deny
  const getLanDiscoveryEnabled: () => boolean = () => {
    const option = props.displayConfigOptions[ConfigOptionKey.ENABLE_LAN_DISCOVERY];
    return option !== 'N';
  };

  const onLanDiscoveryChanged = (checked: boolean) => {
    props.setDisplayConfigOptions({ ...props.displayConfigOptions, [ConfigOptionKey.ENABLE_LAN_DISCOVERY]: checked ? 'N' : '' });
  };

  //default disabled
  const getDirectIP: () => boolean = () => {
    const option = props.displayConfigOptions[ConfigOptionKey.DIRECT_SERVER];
    return option === 'Y';
  };

  const onDirectIPChanged = (checked: boolean) => {
    props.setDisplayConfigOptions({ ...props.displayConfigOptions, [ConfigOptionKey.DIRECT_SERVER]: checked ? 'Y' : '' });
  };

  const str2port = (str: string) => {
    let num = 21118;
    try {
      const tmp = parseInt(str);
      if (!Number.isNaN(tmp) && tmp >= 1 && tmp <= 65535) {
        num = tmp;
      }
    } catch (e) { }
    return num;
  };

  const str2timeout = (str: string) => {
    let num = 10;
    try {
      const tmp = parseInt(str);
      if (!Number.isNaN(tmp) && tmp >= 1 && tmp <= 65535) {
        num = tmp;
      }
    } catch (e) { }
    return num;
  };

  const getDirectIPPort = () => {
    return props.displayConfigOptions[ConfigOptionKey.DIRECT_ACCESS_PORT];
  };

  const onDirectIPPortChanged = (value: string) => {
    const num = str2port(value).toString();
    props.setDisplayConfigOptions({ ...props.displayConfigOptions, [ConfigOptionKey.DIRECT_ACCESS_PORT]: num === '21118' ? '' : num });
  };

  const getwhitelistChecked = () => {
    const option = props.displayConfigOptions[ConfigOptionKey.WHITELIST] ?? '';
    return option.length > 0;
  }

  const onWhitelistClicked = () => {
    const oldOption = props.displayConfigOptions[ConfigOptionKey.WHITELIST] ?? '';
    const whilteTextAreaValue = oldOption.split(',').join('\n');
    whiltelistForm.setFieldValue('whilteTextAreaValue', whilteTextAreaValue);
    setWhiltelistError('');
    setWhiltelistModalOpen(true);
  }

  const handleWhitelistModalCancel = () => {
    setWhiltelistModalOpen(false);
  };

  const handleWhitelistModalClear = () => {
    props.setDisplayConfigOptions({ ...props.displayConfigOptions, [ConfigOptionKey.WHITELIST]: '' });
    setWhiltelistModalOpen(false);
  };

  const handleWhitelistModalSubmit = () => {
    const textAreaValue = whiltelistForm.getFieldValue('whilteTextAreaValue');
    if (!textAreaValue || !isString(textAreaValue)) {
      handleWhitelistModalClear();
      return;
    }
    const textAreaString = textAreaValue as string;
    const ips: string[] = textAreaString.trim().split(/[\s,;\n]+/);
    const ipMatch: RegExp = /^(25[0-5]|2[0-4][0-9]|1[0-9][0-9]|[1-9][0-9]?|0)\.(25[0-5]|2[0-4][0-9]|1[0-9][0-9]|[1-9][0-9]?|0)\.(25[0-5]|2[0-4][0-9]|1[0-9][0-9]|[1-9][0-9]?|0)\.(25[0-5]|2[0-4][0-9]|1[0-9][0-9]|[1-9][0-9]?|0)(\/([1-9]|[1-2][0-9]|3[0-2])){0,1}$/;
    const ipv6Match: RegExp = /^(((?:[0-9A-Fa-f]{1,4}))*((?::[0-9A-Fa-f]{1,4}))*::((?:[0-9A-Fa-f]{1,4}))*((?::[0-9A-Fa-f]{1,4}))*|((?:[0-9A-Fa-f]{1,4}))((?::[0-9A-Fa-f]{1,4})){7})(\/([1-9]|[1-9][0-9]|1[0-1][0-9]|12[0-8])){0,1}$/;
    for (const ip of ips) {
      if (!ipMatch.test(ip) && !ipv6Match.test(ip)) {
        setWhiltelistError(`${plain('Invalid IP')}: ${ip}`);
        return;
      }
    }
    const newWhiteList = ips.join(',');
    props.setDisplayConfigOptions({ ...props.displayConfigOptions, [ConfigOptionKey.WHITELIST]: newWhiteList });
    setWhiltelistModalOpen(false);
  };

  const whiltelistModal = () => {
    return (
      <Modal
        open={whiltelistModalOpen}
        title={plain('IP Whitelisting')}
        onOk={handleWhitelistModalSubmit}
        onCancel={handleWhitelistModalCancel}
        footer={props.editing ? [
          <Button key="cancel" onClick={handleWhitelistModalCancel}>{plain('Cancel')}</Button>,
          <Button key="clear" onClick={handleWhitelistModalClear}>{plain('Clear')}</Button>,
          <Button key="submit" type="primary" onClick={handleWhitelistModalSubmit}>{plain('OK')}</Button>,
        ] : [
          <Button key="close" onClick={handleWhitelistModalCancel}>{plain('Close')}</Button>,
        ]}
      >
        <Form form={whiltelistForm}>
          <Form.Item>
            <p>{plain('whitelist_sep')}</p>
          </Form.Item>
          <Form.Item name="whilteTextAreaValue">
            <ProFormTextArea
              disabled={!props.editing}
              fieldProps={{
                rows: 4,
                maxLength: 2048,
              }}
            />
          </Form.Item>
          {whiltelistError && <Form.Item >
            <p style={{ color: 'red' }}>{whiltelistError}</p>
          </Form.Item>}
        </Form>
      </Modal >
    );
  }

  const getAutoDisconnectAllowed = () => {
    const option = props.displayConfigOptions[ConfigOptionKey.ALLOW_AUTO_DISCONNECT];
    return option === 'Y';
  };

  const onAutoDisconnectAllowedChanged = (checked: boolean) => {
    props.setDisplayConfigOptions({ ...props.displayConfigOptions, [ConfigOptionKey.ALLOW_AUTO_DISCONNECT]: checked ? 'Y' : '' });
  };

  const getAutoDisconnectTimeout = () => {
    return props.displayConfigOptions[ConfigOptionKey.AUTO_DISCONNECT_TIMEOUT];
  };

  const onAutoDisconnectTimeoutChanged = (value: string) => {
    const num = str2timeout(value).toString();
    props.setDisplayConfigOptions({ ...props.displayConfigOptions, [ConfigOptionKey.AUTO_DISCONNECT_TIMEOUT]: num === '10' ? '' : num });
  };

  const tryWrapTooltip = (content: React.ReactNode, tooltip?: string) => {
    if (tooltip) {
      return <Tooltip title={plain(tooltip)}>{content}</Tooltip>;
    }
    return content;
  }

  return (
    <Row>
      <Col span={24}>
        {
          tryWrapTooltip(
            <Checkbox
              disabled={!props.editing}
              checked={!getLanDiscoveryEnabled()}
              onChange={(e) => onLanDiscoveryChanged(e.target.checked)}
            >
              <span>{plain(configOptions[ConfigOptionKey.ENABLE_LAN_DISCOVERY].label)}</span>
            </Checkbox>,
            configOptions[ConfigOptionKey.ENABLE_LAN_DISCOVERY].description
          )
        }
      </Col>
      <Col span={24}>
        {
          tryWrapTooltip(
            <Checkbox
              disabled={!props.editing}
              checked={getDirectIP()}
              onChange={(e) => onDirectIPChanged(e.target.checked)}
            >
              <span>{plain(configOptions[ConfigOptionKey.DIRECT_SERVER].label)}</span>
            </Checkbox>,
            configOptions[ConfigOptionKey.DIRECT_SERVER].description
          )
        }
        {getDirectIP() ? (
          <InputNumber
            disabled={!props.editing}
            min={'1'}
            max={'65535'}
            placeholder={'21118'}
            value={getDirectIPPort()}
            onChange={(value) => onDirectIPPortChanged(value ?? '')}
          />
        ) : null}
      </Col>
      <Col span={24}>
        {
          tryWrapTooltip(
            <Checkbox
              disabled={!props.editing}
              checked={getwhitelistChecked()}
              onClick={(e) => { e.preventDefault(); onWhitelistClicked(); }}
            >
              <span>
                <span>{plain(configOptions[ConfigOptionKey.WHITELIST].label)}</span>
                {getwhitelistChecked() && <>
                  <span style={{ marginLeft: 4, cursor: 'pointer' }} onClick={() => onWhitelistClicked()}>
                    <WarningOutlined style={props.editing ? { color: '#FFCC00' } : {}} />
                  </span>
                </>}
              </span>
            </Checkbox>,
            configOptions[ConfigOptionKey.WHITELIST].description
          )
        }
      </Col>
      {whiltelistModal()}
      <Col span={24}>
        {
          tryWrapTooltip(
            <Checkbox
              disabled={!props.editing}
              checked={getAutoDisconnectAllowed()}
              onChange={(e) => onAutoDisconnectAllowedChanged(e.target.checked)}
            >
              <span>{plain(configOptions[ConfigOptionKey.ALLOW_AUTO_DISCONNECT].label)}</span>
            </Checkbox>,
            configOptions[ConfigOptionKey.ALLOW_AUTO_DISCONNECT].description
          )
        }
        {getAutoDisconnectAllowed() ? (
          <InputNumber
            style={{ marginLeft: 5, width: 150 }}
            disabled={!props.editing}
            min={'1'}
            max={'65535'}
            placeholder={'10'}
            size='small'
            addonAfter={plain("minutes")}
            value={getAutoDisconnectTimeout()}
            onChange={(value) => onAutoDisconnectTimeoutChanged(value ?? '')}
          />
        ) : null
        }
      </Col >
    </Row >
  );
};

export default App;
