import { Checkbox, Col, Row } from 'antd';
import React from 'react';
import { useIntl } from '@umijs/max';
import { ConfigOptionKey } from './common';
import { t } from '@/global';

type AppProps = {
  editing: boolean;
  displayConfigOptions: Record<string, string>;
  setDisplayConfigOptions: React.Dispatch<React.SetStateAction<Record<string, string>>>;
};

const App: React.FC<AppProps> = (props) => {
  const intl = useIntl();

  const plain = (text: string, defaultMessage = '') => t(`pages.Settings.Strategy.${text}`, true, defaultMessage || text, intl) as string;

  const getRemoveWallpaper: () => boolean = () => {
    const option = props.displayConfigOptions[ConfigOptionKey.ALLOW_REMOVE_WALLPAPER];
    return option === 'Y';
  };

  const onRemoveWallpaperChange = (checked: boolean) => {
    props.setDisplayConfigOptions({ ...props.displayConfigOptions, [ConfigOptionKey.ALLOW_REMOVE_WALLPAPER]: checked ? 'Y' : '' });
  };

  return (
    <Row>
      <Col span={24}>
        <Checkbox
          disabled={!props.editing}
          checked={getRemoveWallpaper()}
          onChange={(e) => onRemoveWallpaperChange(e.target.checked)}
        >
          <span>{plain('Remove wallpaper during incoming sessions')}</span>
        </Checkbox>
      </Col>
    </Row >
  );
};

export default App;
