import { Checkbox, Col, Radio, Row, theme } from 'antd';
import { useIntl } from '@umijs/max';
import { t } from '@/global';
import { ConfigOptionKey, USER_BOTH_PASSWORDS, USER_PERMANENT_PASSWORD, USER_TEMPORARY_PASSWORD } from './common';
const { useToken } = theme;

type PasswordProps = {
    editing: boolean;
    displayConfigOptions: Record<string, string>;
    setDisplayConfigOptions: React.Dispatch<React.SetStateAction<Record<string, string>>>;
};

const App: React.FC<PasswordProps> = (props) => {
    const intl = useIntl();
    const { token } = useToken();

    const plain = (text: string, defaultMessage = '') => t(`pages.Settings.Strategy.${text}`, true, defaultMessage || text, intl) as string;

    const getApproveMode: () => string = () => {
        const option = props.displayConfigOptions[ConfigOptionKey.APPROVE_MODE];
        if (['', 'password', 'click'].indexOf(option) >= 0) {
            return option;
        } else {
            return '';
        }
    };

    const onApproveModeChange = (value: string) => {
        props.setDisplayConfigOptions({ ...props.displayConfigOptions, [ConfigOptionKey.APPROVE_MODE]: value });
    };

    const getPasswordType: () => string = () => {
        const option = props.displayConfigOptions[ConfigOptionKey.VERIFICATION_METHOD];
        if ([USER_TEMPORARY_PASSWORD, USER_PERMANENT_PASSWORD, USER_BOTH_PASSWORDS].indexOf(option) >= 0) {
            return option;
        } else {
            return USER_BOTH_PASSWORDS;
        }
    }

    const onPasswordTypeChange = (value: string) => {
        props.setDisplayConfigOptions({ ...props.displayConfigOptions, [ConfigOptionKey.VERIFICATION_METHOD]: value });
    }

    const getTemporaryPasswordLength: () => string = () => {
        const option = props.displayConfigOptions[ConfigOptionKey.TEMPORARY_PASSWORD_LENGTH];
        if (["", "8", "10"].indexOf(option) >= 0) {
            return option;
        } else {
            return "";
        }
    }

    const onTemporaryPasswordLengthChange = (value: string) => {
        props.setDisplayConfigOptions({ ...props.displayConfigOptions, [ConfigOptionKey.TEMPORARY_PASSWORD_LENGTH]: value });
    }

    const getAllowNumericOneTimePassword: () => boolean = () => {
        const option = props.displayConfigOptions[ConfigOptionKey.ALLOW_NUMERIC_ONE_TIME_PASSWORD];
        return option === 'Y';
    };

    const onAllowNumericOneTimePasswordChange = (checked: boolean) => {
        props.setDisplayConfigOptions({ ...props.displayConfigOptions, [ConfigOptionKey.ALLOW_NUMERIC_ONE_TIME_PASSWORD]: checked ? 'Y' : '' });
    };

    const getHideCM: () => boolean = () => {
        const option = props.displayConfigOptions[ConfigOptionKey.ALLOW_HIDE_CM];
        return option === 'Y';
    };

    const onHideCMChange = (checked: boolean) => {
        props.setDisplayConfigOptions({ ...props.displayConfigOptions, [ConfigOptionKey.ALLOW_HIDE_CM]: checked ? 'Y' : '' });
    };

    const getRadioLable = (label: string) => {
        return <span style={{ marginRight: 16, display: "inline-block", color: props.editing ? undefined : token.colorTextQuaternary }}>{plain(label) + " :"}</span>;
    }

    return (
        <Row>
            <Col span={24}>
                {getRadioLable('Approve mode')}
                <Radio.Group
                    disabled={!props.editing}
                    name="approveMode"
                    value={getApproveMode()}
                    onChange={(e) => onApproveModeChange(e.target.value)}
                >
                    <Radio value="password">
                        <span>{plain('Accept sessions via password')}</span>
                    </Radio>
                    <Radio value="click">
                        <span>{plain('Accept sessions via click')}</span>
                    </Radio>
                    <Radio value="">
                        <span>{plain('Accept sessions via both')}</span>
                    </Radio>
                </Radio.Group>
            </Col>
            {
                getApproveMode() !== 'click' ?
                    <Col span={24} style={{ marginTop: '10px' }}>
                        {getRadioLable('Password type')}
                        <br />
                        <Radio.Group disabled={!props.editing} name="passwordType" value={getPasswordType()} onChange={(e) => onPasswordTypeChange(e.target.value)}>
                            <Radio value={USER_TEMPORARY_PASSWORD}><span>{plain('Use one-time password')}</span></Radio>
                            < Radio value={USER_PERMANENT_PASSWORD} >
                                <span>{plain('Use permanent password')}</span></Radio>
                            < Radio value={USER_BOTH_PASSWORDS} > <span>{plain('Use both passwords')}</span></Radio>
                        </Radio.Group>
                    </Col>
                    : null
            }
            {
                getApproveMode() !== 'click' && getPasswordType() !== USER_PERMANENT_PASSWORD ?
                    <Col span={24} style={{ marginTop: '10px' }}>
                        {getRadioLable('One-time password length')}
                        <Radio.Group disabled={!props.editing} name="temporaryPasswordLength" value={getTemporaryPasswordLength()} onChange={(e) => onTemporaryPasswordLengthChange(e.target.value)}>
                            <Radio value={''}><span>6</span></Radio>
                            < Radio value={'8'} ><span>8</span></Radio>
                            < Radio value={'10'} > <span>10</span></Radio>
                        </Radio.Group>
                    </Col>
                    : null
            }
            {
                getApproveMode() !== 'click' && getPasswordType() !== USER_PERMANENT_PASSWORD ?
                    <Col span={24} style={{ marginTop: 12 }}>
                        <Checkbox
                            disabled={!props.editing}
                            checked={getAllowNumericOneTimePassword()}
                            onChange={(e) => onAllowNumericOneTimePasswordChange(e.target.checked)}
                        >
                            <span>{plain('Numeric one-time password')}</span>
                        </Checkbox>
                    </Col>
                    : null
            }
            {
                getApproveMode() === 'password' && getPasswordType() === USER_PERMANENT_PASSWORD ?
                    <Col span={24} style={{ marginTop: 12 }}>
                        <Checkbox
                            disabled={!props.editing}
                            checked={getHideCM()}
                            onChange={(e) => onHideCMChange(e.target.checked)}
                        >
                            <span>{plain('Hide connection management window')}</span>
                        </Checkbox>
                    </Col>
                    : null
            }
        </Row >
    );
};

export default App;
